const clusters = $('Get Top Clusters (Last 24h)').all().map(i => i.json)
const ideas    = $('Get Top Ideas (Last 24h)').all().map(i => i.json)
const allActive = $('Get Stats').all().map(i => i.json)

const yesterday = new Date(Date.now() - 86400000).toISOString()
const newSinceYesterday = allActive.filter(c => c.created_at >= yesterday).length
const hotCount = allActive.filter(c => c.status === 'hot').length
const avgScore = allActive.reduce((s, c) => s + (c.overall_score || 0), 0) / (allActive.length || 1)

return [{
  json: {
    org_id: $('Webhook Trigger (Manual)').first()?.json?.org_id || clusters[0]?.org_id,
    run_id: $('Webhook Trigger (Manual)').first()?.json?.run_id || null,
    status: 'success',
    items_processed: clusters.length,
    digest: {
      date: new Date().toISOString().split('T')[0],
      top_clusters: clusters.map(c => ({
        cluster_id:    c.id,
        title:         c.title,
        overall_score: c.overall_score || 0,
        item_count:    c.item_count || 0,
        top_keywords:  (c.keywords || []).slice(0, 5)
      })),
      top_ideas: ideas.map(i => ({
        idea_id:  i.id,
        title:    i.content?.slice(0, 80) || '',
        type:     i.type,
        platform: i.platform
      })),
      stats: {
        total_clusters:       allActive.length,
        new_since_yesterday:  newSinceYesterday,
        avg_score:            Math.round(avgScore),
        hot_count:            hotCount
      }
    }
  }
}]
